using UnityEngine;

/// <summary>Helpers partilhados pelas condições relacionadas com o player.</summary>
internal static class NpcPlayerConditionUtil
{
    /// <summary>Vai buscar o FormSwitcher do player associado ao NPC (ou null se não existir).</summary>
    public static FormSwitcher GetFormSwitcher(NpcController npc)
    {
        if (npc == null || npc.Player == null) return null;
        return npc.Player.GetComponent<FormSwitcher>();
    }
}

/// <summary>O player tem menos corações do que "hearts".</summary>
[System.Serializable]
public class Condition_HeartsLessThan : NpcCondition
{
    public int hearts = 1;

    public override bool Evaluate(NpcController npc)
    {
        return PlayerProgress.Instance != null && PlayerProgress.Instance.HasFewerHeartsThan(hearts);
    }
}

/// <summary>O player tem mais corações do que "hearts".</summary>
[System.Serializable]
public class Condition_HeartsGreaterThan : NpcCondition
{
    public int hearts = 0;

    public override bool Evaluate(NpcController npc)
    {
        return PlayerProgress.Instance != null && PlayerProgress.Instance.HasMoreHeartsThan(hearts);
    }
}

/// <summary>O player tem este item equipado.</summary>
[System.Serializable]
public class Condition_ItemEquipped : NpcCondition
{
    public ItemData item;

    public override bool Evaluate(NpcController npc)
    {
        return PlayerProgress.Instance != null && PlayerProgress.Instance.HasItemEquipped(item);
    }
}

/// <summary>O player tem pelo menos "amount" Sementes.</summary>
[System.Serializable]
public class Condition_HasSementes : NpcCondition
{
    public int amount = 1;

    public override bool Evaluate(NpcController npc)
    {
        return PlayerProgress.Instance != null && PlayerProgress.Instance.HasSementes(amount);
    }
}

/// <summary>O player tem pelo menos "amount" Runas de Gaia.</summary>
[System.Serializable]
public class Condition_HasRunasDeGaia : NpcCondition
{
    public int amount = 1;

    public override bool Evaluate(NpcController npc)
    {
        return PlayerProgress.Instance != null && PlayerProgress.Instance.HasRunasDeGaia(amount);
    }
}

/// <summary>Este animal já foi libertado pelo player.</summary>
[System.Serializable]
public class Condition_AnimalFreed : NpcCondition
{
    public AnimalFormData animal;

    public override bool Evaluate(NpcController npc)
    {
        return PlayerProgress.Instance != null && PlayerProgress.Instance.HasFreedAnimal(animal);
    }
}

/// <summary>O player está actualmente transformado nesta forma.</summary>
[System.Serializable]
public class Condition_PlayerForm : NpcCondition
{
    public AnimalFormData form;

    public override bool Evaluate(NpcController npc)
    {
        var switcher = NpcPlayerConditionUtil.GetFormSwitcher(npc);
        return switcher != null && form != null && switcher.CurrentForm == form;
    }
}

/// <summary>A forma actual do player pertence a uma destas categorias (GDD).</summary>
[System.Serializable]
public class Condition_PlayerCategory : NpcCondition
{
    public AnimalCategory categories = AnimalCategory.None;

    [Tooltip("Se activo, a forma actual tem de ter TODAS as categorias seleccionadas. Se desactivo, basta ter UMA delas.")]
    public bool requireAll = false;

    public override bool Evaluate(NpcController npc)
    {
        var switcher = NpcPlayerConditionUtil.GetFormSwitcher(npc);
        if (switcher == null || switcher.CurrentForm == null) return false;

        var current = switcher.CurrentForm.categories;

        if (requireAll) return (current & categories) == categories;
        return (current & categories) != 0;
    }
}

/// <summary>O player já desbloqueou este upgrade.</summary>
[System.Serializable]
public class Condition_HasUpgrade : NpcCondition
{
    public UpgradeData upgrade;

    public override bool Evaluate(NpcController npc)
    {
        return PlayerProgress.Instance != null && PlayerProgress.Instance.HasUpgrade(upgrade);
    }
}

/// <summary>
/// O player ainda não tem este upgrade e tem saldo suficiente
/// (UpgradeData.unlockCost/unlockCurrency) para o comprar com
/// Action_BuyUpgrade (Tarefa #20 — Economia). Usar num "+ Adicionar Condição"
/// de branch para mostrar "Comprar Upgrade" só quando aplicável (ex: ocultar
/// se já tens / mostrar "sem sementes suficientes" se não tens saldo).
/// </summary>
[System.Serializable]
public class Condition_CanAffordUpgrade : NpcCondition
{
    public UpgradeData upgrade;

    public override bool Evaluate(NpcController npc)
    {
        var progress = PlayerProgress.Instance;
        if (progress == null || upgrade == null) return false;

        return !progress.HasUpgrade(upgrade) && progress.HasResource(upgrade.unlockCurrency, upgrade.unlockCost);
    }
}

/// <summary>Verifica se o modo difícil está (ou não) activo.</summary>
[System.Serializable]
public class Condition_HardMode : NpcCondition
{
    [Tooltip("true = condição cumpre-se em modo difícil; false = cumpre-se em modo normal.")]
    public bool isHardMode = true;

    public override bool Evaluate(NpcController npc)
    {
        // Fonte única de verdade: IsHardModeActive (Instinto "Juramento
        // Difícil" ligado em enabledUpgradeIds) — a mesma usada por
        // PlayerCombat/PlayerHealthRegen. O antigo campo "progress.hardMode"
        // não era actualizado pelo fluxo normal (loja de Instintos), por isso
        // esta condição nunca correspondia ao dano/regen reais.
        return PlayerProgress.Instance != null && PlayerProgress.Instance.IsHardModeActive == isHardMode;
    }
}

/// <summary>Compara o número de mortes do player numa área.</summary>
[System.Serializable]
public class Condition_DeathsInArea : NpcCondition
{
    public AreaData area;
    public Comparison comparison = Comparison.GreaterOrEqual;
    public int amount = 1;

    public override bool Evaluate(NpcController npc)
    {
        if (PlayerProgress.Instance == null) return false;
        int deaths = PlayerProgress.Instance.GetDeaths(area);
        return NpcConditionUtil.Compare(deaths, comparison, amount);
    }
}

/// <summary>O player venceu o boss deste mundo e ainda não passou pelo evento de "regresso pós-boss".</summary>
[System.Serializable]
public class Condition_ReturningAfterBoss : NpcCondition
{
    public WorldData world;

    public override bool Evaluate(NpcController npc)
    {
        return PlayerProgress.Instance != null && PlayerProgress.Instance.IsReturningAfterBoss(world);
    }
}
